mapper.update:
update bread_review_tbl
set
    rating = #{rating},
    review_content = #{reviewContent},
    updated_date = sysdate
where review_no = #{reviewNo}
  and bread_no = #{breadNo}
  and member_no = #{memberNo}
  and review_status = 'Y'

update bread_review_tbl
set
    review_status = 'N',
    updated_date = sysdate
where review_no = #{reviewNo}
  and bread_no = #{breadNo}
  and member_no = #{memberNo}
  and review_status = 'Y'

mapper.select:
select count(*)
from bread_tbl
where bread_no = #{breadNo}

select order_no
from (
    select o.order_no
    from order_tbl o
    where o.bread_no = #{breadNo}
      and o.member_no = #{memberNo}
      and o.order_status in ('PAID', 'COMPLETED')
      and not exists (
          select 1
          from bread_review_tbl r
          where r.order_no = o.order_no
      )
    order by o.order_date desc, o.order_no desc
)
where rownum = 1
